SELECT t, Name, sum(ValueDelta) AS ValueDeltaAgg FROM (  SELECT t, Name, subName, if(lagInFrame(subName,1,subName) OVER () != subName, 0, Value - lagInFrame(Value,1,0) OVER ()) AS ValueDelta  FROM (   SELECT (intDiv(toUInt32(event_time), 30) * 30) * 1000 AS t, Name, 'test2' AS subName, max(Value) AS Value   FROM default.test_grafana WHERE event_date >= toDate(1735787045) AND event_date <= toDate(1735790706) AND event_time >= toDateTime(1735787045) AND event_time <= toDateTime(1735790706)   GROUP BY Name, subName, t    ORDER BY Name, subName, t  ) ) GROUP BY Name, t ORDER BY Name, t